        "For MCQs, select the single best option. For written answers, be concise and precise."
      ]
    },
    "blueprint": {
      "learningOutcomeCoverage": [
        {
          "outcome": "Students will define a solution as a homogeneous mixture.",
          "questionRefs": [
            "q1",
            "q2"
          ]
        },
        {
          "outcome": "Students will identify the solute and solvent in common examples.",
          "questionRefs": [
