            "q7"
          ]
        }
      ],
      "difficultyDistribution": {
        "easy": 43,
        "medium": 43,
        "hard": 14
      },
      "bloomsDistribution": {
        "recall": 29,
        "understanding": 57,
        "application": 14,
        "analysis": 0,
