      },
      "questionDistribution": {
        "mcq": 3,
        "shortAnswer": 4
      },
      "timeAllocation": [
        {
          "section": "MCQs",
          "minutes": 5
        },
        {
          "section": "Very Short Answer & Short Answers",
          "minutes": 10
        }
      ]
    },
    "mcq": [
      {
        "id": "q1",
        "questionSubtype": "veryShortAnswer",
        "question": "Define a solution in your own words.",
        "answer": "A homogeneous mixture of two or more substances where the composition is uniform throughout.",
        "expectedLength": "One sentence definition mentioning 'homogeneous' and 'uniform'.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO1"
        ],
        "topicCoverage": [
          "Definition of Solution"
        ],
        "difficulty": "easy",
        "bloomsLevel": "recall"
      },
      {
        "id": "q2",
        "questionSubtype": "veryShortAnswer",
        "question": "Identify the solute and solvent in vinegar (a mixture of acetic acid and water).",
        "answer": "Solute: Acetic acid; Solvent: Water.",
        "expectedLength": "Identification of both components clearly.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO2"
        ],
        "topicCoverage": [
          "Components of Solutions"
        ],
        "difficulty": "easy",
        "bloomsLevel": "understanding"
      },
      {
        "id": "q3",
        "questionSubtype": "mcq",
        "question": "Which of the following best describes a solution?",
        "options": [
          "A. A mixture where particles settle down over time.",
          "B. A heterogeneous mixture with visible distinct parts.",
          "C. A homogeneous mixture with uniform composition throughout.",
          "D. A mixture that can be easily separated by filtration."
        ],
        "answer": "C",
        "explanation": "A solution is defined as a homogeneous mixture where the solute particles are uniformly distributed at the molecular level and do not settle or scatter light significantly enough to make it heterogeneous.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO3"
        ],
        "topicCoverage": [
          "Properties of Solutions vs. Suspensions"
        ],
        "difficulty": "medium",
        "bloomsLevel": "understanding"
      },
      {
        "id": "q4",
        "questionSubtype": "mcq",
        "question": "In a solution of brass (an alloy of copper and zinc), which component typically acts as the solvent?",
        "options": [
          "A. Zinc, because it is added to change properties.",
          "B. Copper, usually present in larger quantity acting as the base structure.",
          "C. Both are solutes equally.",
          "D. Neither; alloys do not have a solvent."
        ],
        "answer": "B",
        "explanation": "In solid solutions like brass (an alloy), the metal present in the larger amount acts as the solvent, while the other is the solute. Copper is typically the major component.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO2"
        ],
        "topicCoverage": [
          "Solid Solutions and Solvent Roles"
        ],
        "difficulty": "medium",
        "bloomsLevel": "application"
      },
      {
        "id": "q5",
        "questionSubtype": "shortAnswer",
        "question": "Explain why muddy water is not considered a solution, whereas salt water is.",
        "answer": "Muddy water contains large particles that are visible and settle down over time (suspension), making it heterogeneous. Salt water has dissolved particles at the molecular level (<1 nm) which do not settle and form a uniform mixture (solution).",
        "expectedLength": "2-3 points contrasting particle size, visibility/settling, and homogeneity.",
        "marks": 2,
        "learningOutcomeIds": [
          "LO3"
        ],
        "topicCoverage": [
          "Differentiation: Solution vs. Suspension"
        ],
        "difficulty": "medium",
        "bloomsLevel": "analysis"
      },
      {
        "id": "q6",
        "questionSubtype": "shortAnswer",
        "question": "Give one example of a gaseous solution and identify its solute and solvent.",
        "answer": "Example: Air. Solvent: Nitrogen (approx 78%). Solute: Oxygen, Argon, etc. (minor components). Note: The state is determined by the major component (Nitrogen).",
        "expectedLength": "Correct example with correct identification of solute/solvent based on quantity.",
        "marks": 2,
        "learningOutcomeIds": [
          "LO1",
          "LO2"
        ],
        "topicCoverage": [
          "States of Solutions (Gaseous)"
        ],
        "difficulty": "medium",
        "bloomsLevel": "application"
      },
      {
        "id": "q7",
        "questionSubtype": "shortAnswer",
        "question": "A student claims that 'dissolving' is the same as 'melting'. Correct this misconception with a brief explanation.",
        "answer": "Dissolving involves mixing two substances where one disperses in another (e.g., salt in water), forming a mixture. Melting is a phase change of a single pure substance from solid to liquid due to heat, without adding another component.",
        "expectedLength": "Clear distinction between the process of dissolving (mixture formation) and melting (phase transition).",
        "marks": 2,
        "learningOutcomeIds": [
          "LO3"
        ],
        "topicCoverage": [
          "Misconceptions: Dissolving vs. Melting"
        ],
        "difficulty": "hard",
        "bloomsLevel": "analysis"
      }
    ],
    "shortAnswer": [],
    "longAnswer": [],
    "answerKey": {
      "mcq": [
        {
          "id": "q3",
          "answer": "C. A homogeneous mixture with uniform composition throughout.",
          "explanation": "Solutions are defined by their homogeneity and lack of settling, unlike suspensions or colloids which may scatter light or settle.",
          "marks": 1,
          "questionSubtype": "mcq"
        },
        {
          "id": "q4",
          "answer": "B. Copper, usually present in larger quantity acting as the base structure.",
          "explanation": "In solid solutions like alloys (brass), the component with the higher concentration acts as the solvent.",
          "marks": 1,
          "questionSubtype": "mcq"
        }
      ],
      "shortAnswer": [
        {
          "id": "q5",
          "answer": "Muddy water is a suspension because it has visible particles that settle down and is heterogeneous. Salt water is a solution because the salt dissolves completely, forming a homogeneous mixture where particles are too small to see or filter.",
          "rubric": [
            "1 mark for correctly identifying muddy water as a suspension/heterogeneous/settling",
            "1 mark for correctly identifying salt water as a solution/homogeneous/non-settling"
          ],
          "marks": 2,
          "questionSubtype": "shortAnswer"
        },
        {
          "id": "q6",
          "answer": "Example: Air. Solvent: Nitrogen (major component). Solute: Oxygen and other gases.",
          "rubric": [
            "1 mark for providing a correct gaseous solution example (e.g., Air)",
            "1 mark for correctly identifying the solvent as the major gas (Nitrogen) and solute as minor components"
          ],
          "marks": 2,
          "questionSubtype": "shortAnswer"
        },
        {
          "id": "q7",
          "answer": "Dissolving is a physical process where two substances mix to form a solution (mixture). Melting is the phase change of a single substance from solid to liquid. Dissolving requires another substance; melting does not.",
          "rubric": [
            "1 mark for defining dissolving as mixing/substance dispersion",
            "1 mark for distinguishing it from melting which is a pure substance phase change"
          ],
          "marks": 2,
          "questionSubtype": "shortAnswer"
        }
      ],
      "longAnswer": [],
      "generalMarkingGuidance": [
        "Award marks point-wise for each valid idea.",
        "Accept equivalent scientific wording if the meaning is correct (e.g., 'uniform' vs 'homogeneous').",
        "For conceptual questions, partial credit may be given for identifying key terms like 'solute', 'solvent', or 'heterogeneous'.",
        "Ensure students distinguish between physical mixing and phase changes."
      ]
    }
  }
}
